class Solution {
public:
    vector<int> spiralOrder(vector<vector<int>>& m) {
        vector<int> res; if(m.empty()) return res;
        int t=0,b=m.size()-1,l=0,r=m[0].size()-1;
        while(t<=b&&l<=r){
            for(int c=l;c<=r;c++) res.push_back(m[t][c]); t++;
            for(int i=t;i<=b;i++) res.push_back(m[i][r]); r--;
            if(t<=b){ for(int c=r;c>=l;c--) res.push_back(m[b][c]); b--; }
            if(l<=r){ for(int i=b;i>=t;i--) res.push_back(m[i][l]); l++; }
        }
        return res;
    }
};
